.home-services {
  position: relative;
  width: 100vw;
  height: 100svh;
  padding: 8rem 2rem;
  overflow: hidden;
}

.home-services-top-bar {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
}

.home-services-bottom-bar {
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
