.home-services-top-bar .container,
.home-services-bottom-bar .container {
  display: flex;
  justify-content: space-between;
}

.home-services-header {
  position: relative;
  width: 100%;
  text-align: center;
  transform: translateY(300%);
  will-change: transform;
}

.home-services .cards {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100svh;
  display: flex;
  justify-content: center;
  z-index: -1;
  background-color: var(--base-100);
}

.home-services .cards-container {
  position: relative;
  width: 75%;
  height: 100%;
  margin-top: 4rem;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 4rem;
}

.home-services .cards-container .card {
  flex: 1;
  position: relative;
  aspect-ratio: 5/7;
  perspective: 1000px;
}

.home-services .cards-container .card .card-wrapper {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100%;
  height: 100%;
  animation: floating 2s infinite ease-in-out;
}

.home-services .card .card-title {
  width: 100%;
  display: flex;
  justify-content: space-between;
}

.home-services .card p {
  font-size: 0.8rem;
}

@keyframes floating {
  0% {
    transform: translate(-50%, -50%);
  }
  50% {
    transform: translate(-50%, -55%);
  }
  100% {
    transform: translate(-50%, -50%);
  }
}

.home-services #card-1 .card-wrapper {
  animation-delay: 0;
}

.home-services #card-2 .card-wrapper {
  animation-delay: 0.25s;
}

.home-services #card-3 .card-wrapper {
  animation-delay: 0.5s;
}

.home-services .flip-card-inner {
  position: relative;
  width: 100%;
  height: 100%;
  transform-style: preserve-3d;
}

.home-services .flip-card-front,
.home-services .flip-card-back {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 8px;
  backface-visibility: hidden;
  overflow: hidden;
}

