}

.home-services #card-3 .flip-card-front {
  background-color: var(--accent-3);
}

.home-services .flip-card-back {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: 2rem;
  background-color: #fff;
  transform: rotateY(180deg);
}

