  position: absolute;
  top: 120%;
  left: 50%;
  transform: translateX(-50%);
  width: 60px;
  height: 60px;
  opacity: 0;
  will-change: transform, opacity;
}

.transition-logo img {
  width: 100%;
  height: 100%;
  object-fit: contain;
}

.mask-transition {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 99999;
  pointer-events: none;
  display: none;
}

